import 'package:flutter/material.dart';
import 'package:pooja_sindhu/core/theme/app_colors.dart';
import 'package:pooja_sindhu/core/theme/app_spacing.dart';
class BookingFlowStepper extends StatelessWidget { const BookingFlowStepper({super.key, required this.steps, required this.currentStep}); final List<String> steps; final int currentStep; @override Widget build(BuildContext context) => Padding(padding: const EdgeInsets.symmetric(horizontal: AppSpacing.md, vertical: AppSpacing.sm), child: Row(children: List.generate(steps.length * 2 - 1, (index) { if (index.isOdd) return Expanded(child: Container(height: 2, color: index ~/ 2 < currentStep ? AppColors.primary : AppColors.divider)); final step = index ~/ 2; final selected = step <= currentStep; return Column(children: [CircleAvatar(radius: 16, backgroundColor: selected ? AppColors.primary : AppColors.divider, child: Text('${step + 1}', style: const TextStyle(color: Colors.white))), const SizedBox(height: 4), Text(steps[step], style: const TextStyle(fontSize: 10))]); }))); }
